  import sailpoint.api.SailPointContext;

  import org.apache.log4j.Logger; 
  import org.apache.log4j.Level;
  import org.apache.commons.logging.LogFactory;

  // TOYOTA Loger for Advanced analytics
  // Must log to error and prefix with dbLogPrefix
  Logger dblog = Logger.getLogger(  "toyota.databaseSyslog" );
  String dbLogPrefix = "Toyota-ERROR: ";


  /*******
	Search Azure for existance of email
  *******/  
  public void toyotaLogger( SailPointContext context, String logMessage ) {
  	dblog.error( dbLogPrefix + logMessage );
  }
